172→    public static void refreshMetadata(AccountStore accountStore, SiteStore siteStore) {
173→        AnalyticsMetadata metadata = new AnalyticsMetadata();
174→
175→        metadata.setUserConnected(FluxCUtils.isSignedInWPComOrHasWPOrgSite(accountStore, siteStore));
176→        metadata.setWordPressComUser(accountStore.hasAccessToken());
177→        metadata.setJetpackUser(isJetpackUser(siteStore));
178→        metadata.setNumBlogs(siteStore.getSitesCount());
179→        metadata.setUsername(accountStore.getAccount().getUserName());
180→        metadata.setEmail(accountStore.getAccount().getEmail());
181→        String scheme = BuildConfig.DEBUG ? "debug" : BuildConfig.FLAVOR;
182→        metadata.setAppScheme(scheme);
183→        if (siteStore.hasSite()) {
184→            metadata.setGutenbergEnabled(isGutenbergEnabledOnAnySite(siteStore.getSites()));
185→        }
186→
187→        AnalyticsTracker.refreshMetadata(metadata);
188→    }
