240→    /**
241→     * Bump Analytics for the passed Stat and add blog details into properties.
242→     *
243→     * @param stat       The Stat to bump
244→     * @param site       The site object
245→     * @param properties Properties to attach to the event
246→     */
247→    public static void trackWithSiteDetails(AnalyticsTrackerWrapper analyticsTrackerWrapper,
248→                                            AnalyticsTracker.Stat stat,
249→                                            @Nullable SiteModel site,
250→                                            @Nullable Map<String, Object> properties) {
251→        if (site == null || !SiteUtils.isAccessedViaWPComRest(site)) {
252→            AppLog.w(AppLog.T.STATS, "The passed blog obj is null or it's not a wpcom or Jetpack."
253→                                     + " Tracking analytics without blog info");
254→            if (properties == null) {
255→                analyticsTrackerWrapper.track(stat);
256→            } else {
257→                analyticsTrackerWrapper.track(stat, properties);
258→            }
259→            return;
260→        }
261→
262→        if (SiteUtils.isAccessedViaWPComRest(site)) {
263→            if (properties == null) {
264→                properties = new HashMap<>();
265→            }
266→            properties.put(BLOG_ID_KEY, site.getSiteId());
267→            properties.put(IS_JETPACK_KEY, site.isJetpackConnected());
268→            properties.put(SITE_TYPE_KEY, AnalyticsSiteType.toStringFromSiteModel(site));
269→        }
270→
271→        if (properties == null) {
272→            analyticsTrackerWrapper.track(stat);
273→        } else {
274→            analyticsTrackerWrapper.track(stat, properties);
275→        }
276→    }
