542→    /*
543→     * Converts the JSON string of a railcar to a properties list using the existing json key names
544→     */
545→    private static Map<String, Object> railcarJsonToProperties(@NonNull String railcarJson) {
546→        Map<String, Object> properties = new HashMap<>();
547→        try {
548→            JSONObject jsonRailcar = new JSONObject(railcarJson);
549→            Iterator<String> iter = jsonRailcar.keys();
550→            while (iter.hasNext()) {
551→                String key = iter.next();
552→                Object value = jsonRailcar.get(key);
553→                properties.put(key, value);
554→            }
555→        } catch (JSONException e) {
556→            AppLog.e(AppLog.T.READER, e);
557→        }
558→
559→        return properties;
560→    }
