562→    public static Map<String, Object> getMediaProperties(Context context, boolean isVideo, Uri mediaURI, String path) {
563→        Map<String, Object> properties = new HashMap<>();
564→        if (context == null) {
565→            AppLog.e(AppLog.T.MEDIA, "In order to track media properties Context cannot be null.");
566→            return properties;
567→        }
568→        if (mediaURI == null && TextUtils.isEmpty(path)) {
569→            AppLog.e(AppLog.T.MEDIA, "In order to track media properties mediaURI and path cannot be both null!!");
570→            return properties;
571→        }
572→
573→        if (mediaURI != null) {
574→            path = MediaUtils.getRealPathFromURI(context, mediaURI);
575→        }
576→
577→        if (TextUtils.isEmpty(path)) {
578→            return properties;
579→        }
580→
581→        // File not found
582→        File file = new File(path);
583→        try {
584→            if (!file.exists()) {
585→                AppLog.e(AppLog.T.MEDIA,
586→                        "Can't access the media file. It doesn't exists anymore!! Properties are not being tracked.");
587→                return properties;
588→            }
589→
590→            if (file.lastModified() > 0L) {
591→                long ageMS = System.currentTimeMillis() - file.lastModified();
592→                properties.put("age_ms", ageMS);
593→            }
594→        } catch (SecurityException e) {
595→            AppLog.e(AppLog.T.MEDIA, "Can't access the media file. Properties are not being tracked.", e);
596→            return properties;
597→        }
598→
599→        String mimeType = MediaUtils.getMediaFileMimeType(file);
600→        properties.put("mime", mimeType);
601→
602→        String fileName = MediaUtils.getMediaFileName(file, mimeType);
603→        String fileExtension = MimeTypeMap.getFileExtensionFromUrl(fileName).toLowerCase(Locale.ROOT);
604→        properties.put("ext", fileExtension);
605→
606→        if (!isVideo) {
607→            int[] dimensions = ImageUtils.getImageSize(Uri.fromFile(file), context);
608→            double megapixels = dimensions[0] * dimensions[1];
609→            megapixels = megapixels / 1000000;
610→            megapixels = Math.floor(megapixels);
611→            properties.put("megapixels", (int) megapixels);
612→        } else {
613→            long videoDurationMS = VideoUtils.getVideoDurationMS(context, file);
614→            properties.put("duration_secs", (int) videoDurationMS / 1000);
615→        }
616→
617→        properties.put("bytes", file.length());
618→
619→        return properties;
620→    }
